import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, DateRangeFilter, Select, addToast, CatalogTableSkeleton } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import type { SelectOption } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { AdvancePaymentDto } from '../../../services/kt/models';
import { formatDateLocal, formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { useVoucherListFilterState } from '../../../hooks/useVoucherListFilterState';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { tamUngLabels } from '../../../constants/tamUngLabels';
import { TAM_UNG_LIST_INIT_FORM } from '../../../constants/tamUngInit';
import {
  formatProcessingLevelFromOptions,
  resolveProcessingLevelSelectOptions,
} from '../../../utils/voucherProcessingLevelOptions';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import {
  DEFAULT_VOUCHER_LIST_PAGE_SIZE,
  VoucherListPagination,
  type VoucherListPageSize,
} from '../../../components/list/VoucherListPagination';
import { useVoucherListTableBusy } from '../../../components/list/useVoucherListTableBusy';
import { useVoucherListActions } from '../../../hooks/useVoucherListActions';
import { ProcessingLevelApproveModal } from '../../../components/voucher/ProcessingLevelApproveModal';

const PAGE_SIZE = DEFAULT_VOUCHER_LIST_PAGE_SIZE;
const TEST_PREFIX = 'kt-tam-ung';

const TamUngListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const {
    initialized,
    fromDate,
    setFromDate,
    toDate,
    setToDate,
    processingLevel,
    setProcessingLevel,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(LIST_FILTER_SCOPE.tamUng);
  const { processingLevelOptions, defaultProcessingLevel } = useVoucherInitData(TAM_UNG_LIST_INIT_FORM);
  const { canCreate, canApprove } = useVoucherListActions(TAM_UNG_LIST_INIT_FORM);

  const [items, setItems] = useState<AdvancePaymentDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<VoucherListPageSize>(PAGE_SIZE);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [approving, setApproving] = useState(false);
  const levelFilterOptions = useMemo(() => {
    const levels = resolveProcessingLevelSelectOptions(processingLevelOptions, defaultProcessingLevel);
    return [{ value: '', label: tamUngLabels.filterAllLevels }, ...levels];
  }, [processingLevelOptions, defaultProcessingLevel]);

  const selectableRows = useMemo(() => items.filter(row => row.status === 'Draft'), [items]);
  const allSelectableSelected = selectableRows.length > 0 && selectableRows.every(row => selectedIds.includes(row.id));
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const handleSearch = () => {
    pulseSearch(() => {
      resetPage();
      setSelectedIds([]);
      setReloadKey(k => k + 1);
    });
  };
  const refresh = () => {
    pulseSearch(() => {
      setSelectedIds([]);
      setReloadKey(k => k + 1);
    });
  };

  const setPageSize = (size: number) => {
    setPageSizeState(size as VoucherListPageSize);
    resetPage();
    setSelectedIds([]);
  };

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      ktService.getAdvancePayments({
        fromDate,
        toDate,
        processingLevel: processingLevel || undefined,
        page,
        pageSize,
      })
        .then(res => { if (!cancelled) { setItems(res.items); setTotalCount(res.totalCount); } })
        .catch(err => {
          if (!cancelled) {
            dispatch(addToast({ message: getApiErrorMessage(err, tamUngLabels.listLoadError), type: 'error' }));
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, fromDate, toDate, processingLevel, page, pageSize, reloadKey, dispatch]);

  const toggleSelectAll = () => {
    if (allSelectableSelected) {
      const currentPageIds = new Set(selectableRows.map(row => row.id));
      setSelectedIds(prev => prev.filter(id => !currentPageIds.has(id)));
      return;
    }
    const merged = new Set([...selectedIds, ...selectableRows.map(row => row.id)]);
    setSelectedIds([...merged]);
  };

  const handleBatchApproveConfirm = async (nextLevel: string) => {
    setApproving(true);
    try {
      await ktService.batchUpdateAdvancePaymentProcessingLevel(selectedIds, nextLevel);
      dispatch(addToast({ message: tamUngLabels.approveSuccess, type: 'success' }));
      setShowApproveModal(false);
      setSelectedIds([]);
      setReloadKey(k => k + 1);
    } catch (error: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(error, tamUngLabels.approveError), type: 'error' }));
    } finally {
      setApproving(false);
    }
  };

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-hand-holding-usd" /> {tamUngLabels.listPageTitle}</h1></div>
        <div className={erp.headerActions}>
          {canApprove && (
            <Button
              variant="secondary"
              data-testid={`${TEST_PREFIX}-batch-approve-btn`}
              disabled={selectedIds.length === 0}
              onClick={() => setShowApproveModal(true)}
            >
              <i className="fas fa-check-double" /> {tamUngLabels.approveButton}
            </Button>
          )}
          {canCreate && (
            <Button
              variant="primary"
              data-testid={`${TEST_PREFIX}-create-btn`}
              onClick={() => navigate('/kt/tam-ung/them')}
            >
              <i className="fas fa-plus" /> {tamUngLabels.createButton}
            </Button>
          )}
        </div>
      </div>

      {selectedIds.length > 0 && (
        <div className={erp.batchBar} data-testid={`${TEST_PREFIX}-batch-bar`}>
          <span>{tamUngLabels.selectedPrefix} {selectedIds.length}</span>
          <button
            type="button"
            className={erp.batchBarLink}
            data-testid={`${TEST_PREFIX}-batch-clear`}
            onClick={() => setSelectedIds([])}
          >
            {tamUngLabels.clearAll}
          </button>
        </div>
      )}

      <div className={erp.filtersBar} data-testid={`${TEST_PREFIX}-filters`}>
        <DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v: DateRangeValue) => { setFromDate(v.fromDate); setToDate(v.toDate); resetPage(); }} />
        <div data-testid={`${TEST_PREFIX}-filter-processingLevel`}>
          <Select value={processingLevel} onChange={e => { setProcessingLevel(e.target.value); resetPage(); }} options={levelFilterOptions} />
        </div>
        <ListSearchRefreshButtons testIdPrefix={TEST_PREFIX} onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>
      <div className={erp.tableCard}>
        {showTableLoading ? (
          <CatalogTableSkeleton
            rows={Math.min(pageSize, 8)}
            data-testid={`${TEST_PREFIX}-table-skeleton`}
          />
        ) : items.length === 0 ? <div className={erp.empty}>{tamUngLabels.empty}</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th className={erp.colCheck}>
                    <input
                      type="checkbox"
                      data-testid={`${TEST_PREFIX}-select-all`}
                      checked={allSelectableSelected}
                      disabled={selectableRows.length === 0}
                      onChange={toggleSelectAll}
                      aria-label="Chọn tất cả"
                    />
                  </th>
                  <th>{tamUngLabels.colCode}</th>
                  <th>{tamUngLabels.colDate}</th>
                  <th>{tamUngLabels.colCustomer}</th>
                  <th>{tamUngLabels.colDescription}</th>
                  <th className={erp.colRight}>{tamUngLabels.colAmount}</th>
                  <th>{tamUngLabels.colProcessingLevel}</th>
                </tr>
              </thead>
              <tbody>{items.map(r => (
                <tr key={r.id}>
                  <td className={erp.colCheck}>
                    <input
                      type="checkbox"
                      data-testid={`${TEST_PREFIX}-row-${r.id}-select`}
                      checked={selectedIds.includes(r.id)}
                      disabled={r.status !== 'Draft'}
                      onChange={e => {
                        const checked = e.target.checked;
                        setSelectedIds(prev => checked ? [...prev, r.id] : prev.filter(x => x !== r.id));
                      }}
                      aria-label={`Chọn ${r.code}`}
                    />
                  </td>
                  <td>
                    <button type="button" className={erp.codeLink} onClick={() => navigate(`/kt/tam-ung/${r.id}`)}>
                      <code>{r.code}</code>
                    </button>
                  </td>
                  <td>{formatDateLocal(r.voucherDate)}</td>
                  <td>{r.customerName ?? r.customerCode ?? '—'}</td>
                  <td>{r.description ?? '—'}</td>
                  <td className={erp.colRight}>{formatVnd(r.amount)}</td>
                  <td data-testid={`${TEST_PREFIX}-row-${r.id}-processing-level`}>
                    {formatProcessingLevelFromOptions(r.processingLevel, processingLevelOptions)}
                  </td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
        {!showTableLoading && (
          <VoucherListPagination
            testIdPrefix={TEST_PREFIX}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); setSelectedIds([]); }}
            onPageSizeChange={setPageSize}
          />
        )}
      </div>
      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={defaultProcessingLevel ?? ''}
        levelOptions={processingLevelOptions}
        onConfirm={handleBatchApproveConfirm}
        saving={approving}
        testIdPrefix={TEST_PREFIX}
      />
    </div>
  );
};

export default TamUngListPage;
